UPDATE SAAS_WORKSPACE
SET
workSpaceName = #{request.workSpaceName},
description = #{request.description},
type = #{request.type}
WHERE workSpaceNo = #{workSpaceNo}
AND ownerNo = #{ownerNo}
AND deletedDt IS NULL

UPDATE SAAS_WORKSPACE_MEMBER
SET role = #{role},
updatedDt = NOW()
WHERE workSpaceNo = #{workSpaceNo}
AND memberNo = #{targetMemberNo}
AND deletedDt IS NULL

UPDATE SAAS_WORKSPACE_MEMBER
SET deletedDt = NOW()
WHERE workSpaceNo = #{workSpaceNo}
AND memberNo = #{memberNo}
AND deletedDt IS NULL

UPDATE SAAS_WORKSPACE_INVITE
SET usedCount = usedCount + 1
WHERE inviteToken = #{inviteToken}
